def check_copyright():
    """
    检查版权信息是否完整
    如果版权信息被删除或修改，程序将无法运行
    不依赖行号，使用多种检查方法
    """
    try:
        current_file = os.path.abspath(__file__)
        
        with open(current_file, 'r', encoding='utf-8') as f:
            content = f.read()
        
        # 检查文件开头的基本版权信息
        header_section = content[:500]
        
        # 基础版权信息检查
        basic_copyright = [
            "星视 GSUN View",
            "Guoyou Sun",
            "孙国佑", 
            "http://sunguoyou.lamost.org/"
        ]
        
        found_count = sum(1 for check_str in basic_copyright if check_str in header_section)
        if found_count < 2:  # 至少需要2项存在
            print("错误：版权保护机制被触发！")
            print("检测到版权信息被篡改或删除。")
            print("本软件受版权保护，未经授权不得修改。")
            print("请联系作者获取授权：http://sunguoyou.lamost.org/")
            sys.exit(1)
        
        # 检查关键版权字符串的存在性（不依赖位置）
        required_copyright_strings = [
            "Guoyou Sun",
            "孙国佑",
            "sunguoyou.lamost.org",
            "天体收藏家",
            "星视 GSUN View"
        ]
        
        # 检查每个关键字符串在文件中出现的次数
        for check_str in required_copyright_strings:
            count = content.count(check_str)
            if count == 0:
                print(f"错误：版权保护机制被触发！")
                print(f"检测到关键版权信息被删除：{check_str}")
                print("本软件受版权保护，未经授权不得修改。")
                print("请联系作者获取授权：http://sunguoyou.lamost.org/")
                sys.exit(1)
        
        # 检查版权信息的完整性（不依赖位置标记）
        # 检查关键版权字符串的出现次数
        required_copyright_counts = {
            "Guoyou Sun": 20,   
            "孙国佑": 20,       
            "sunguoyou.lamost.org": 20,   
            "天体收藏家": 10,   
            "星视 GSUN View": 20 
        }
        
        for check_str, min_count in required_copyright_counts.items():
            count = content.count(check_str)
            if count < min_count:
                print(f"错误：版权保护机制被触发！")
                print(f"检测到关键版权信息被删除：{check_str}")
                print(f"当前出现次数：{count}，要求：{min_count}")
                print("本软件受版权保护，未经授权不得修改。")
                print("请联系作者获取授权：http://sunguoyou.lamost.org/")
                sys.exit(1)
        
        # 检查关键函数的完整性
        if "def check_copyright():" not in content:
            print("错误：版权保护机制被触发！")
            print("检测到版权检查函数被删除。")
            print("本软件受版权保护，未经授权不得修改。")
            print("请联系作者获取授权：http://sunguoyou.lamost.org/")
            sys.exit(1)
            
        return True
        
    except Exception as e:
        print(f"版权验证失败：{str(e)}")
        print("本软件受版权保护，无法运行。")
        sys.exit(1)

# 隐藏的版权保护函数（在程序运行时检查）
def hidden_copyright_check():
    """隐藏的版权检查，在程序运行过程中触发"""
    try:
        import inspect
        frame = inspect.currentframe()
        caller_frame = frame.f_back
        caller_file = caller_frame.f_code.co_filename
        
        if caller_file.endswith('GSUNView.py'):
            with open(caller_file, 'r', encoding='utf-8') as f:
                content = f.read()
            
            # 检查关键位置的版权信息（只检查确实有版权信息的位置）
            key_positions = [6055]  # 只检查确实有作者信息的位置
            for pos in key_positions:
                if pos < len(content):
                    section = content[max(0, pos-100):min(len(content), pos+100)]
                    # 检查是否有版权信息，如果确实没有才触发保护
                    if "作者" in section and ("Guoyou Sun" not in section and "孙国佑" not in section):
                        print("隐藏版权保护被触发：关键位置版权信息被删除")
                        sys.exit(1)
    except:
        pass  # 静默失败，不影响正常使用

