class AstapSolveThread(QThread):
    """ASTAP 盲解线程"""
    finished = pyqtSignal(bool, int, str)  # success, exit_code, message
    progress = pyqtSignal(int, str)  # value, message
    
    def __init__(self, astap_path, fits_file, settings):
        super().__init__()
        self.astap_path = astap_path
        self.fits_file = fits_file
        self.settings = settings
    
    def run(self):
        try:
            self.progress.emit(10, "正在调用 ASTAP...")
            
            success, exit_code = astrometric_solver(
                astap_path=self.astap_path,
                fits_file=self.fits_file,
                search_radius=self.settings['search_radius'],
                fov=self.settings['fov'],
                star_count=self.settings['star_count'],
                min_star_pixels=self.settings['min_pixels'],
                use_sip=self.settings['use_sip'],
                update_header=self.settings['update_header']
            )
            
            self.progress.emit(90, "解析完成")
            
            if success:
                self.finished.emit(True, exit_code, "")
            else:
                error_desc = ERROR_CODES.get(exit_code, f"未知错误 (错误码: {exit_code})")
                self.finished.emit(False, exit_code, error_desc)
        
        except Exception as e:
            import traceback
            traceback.print_exc()
            self.finished.emit(False, -1, str(e))


