    def set_window_icon_from_base64(self):
        """从Base64字符串设置窗口图标"""
        try:
            # Base64编码的logo.jpg图片数据
            logo_base64 = ""
            
            # 将Base64字符串转换为QPixmap
            image_data = base64.b64decode(logo_base64)
            pixmap = QPixmap()
            if pixmap.loadFromData(image_data):
                # 创建QIcon并设置为窗口图标
                icon = QIcon(pixmap)
                self.setWindowIcon(icon)
                print("窗口图标设置成功")
            else:
                print("加载logo图片失败")
                
        except Exception as e:
            print(f"设置窗口图标失败: {e}")
    
