    def load_shortcuts_config(self):
        """从JSON文件加载快捷键配置"""
        try:
            if os.path.exists('shortcuts.json'):
                with open('shortcuts.json', 'r', encoding='utf-8') as f:
                    data = json.load(f)
                    self.shortcuts_config = data.get('shortcuts', {})
            else:
                self.shortcuts_config = {}
        except Exception as e:
            print(f"加载快捷键配置时出错: {e}")
            self.shortcuts_config = {}
    
    def get_shortcut(self, key):
        """获取指定功能的快捷键"""
        return self.shortcuts_config.get(key, {}).get('current', None)
    
    def reload_shortcuts(self):
        """重新加载快捷键配置并应用到所有动作"""
        self.load_shortcuts_config()
        self.apply_shortcuts_to_actions()
    
    def apply_shortcuts_to_actions(self):
        """将快捷键应用到所有动作"""
        shortcut_map = {
            'load_image': self.load_action,
            'pause': self.pause_action,
            'report_coord': self.report_coord_action,
            'stack': self.stack_action,
            'process_parse': self.process_parse_action,
            'report': self.report_action,
            'mpc_report': self.mpc_report_action,
            'prev_image': self.prev_image_action,
            'next_image': self.next_image_action,
            'auto_histogram': self.auto_histogram_action,
            'horizontal_flip': self.horizontal_flip_action,
            'vertical_flip': self.vertical_flip_action,
            'rotate_left': self.rotate_left_action,
            'rotate_right': self.rotate_right_action,
            'save_image': self.save_as_image_action,
            'save_overwrite': self.save_image_action,
            'process_astap_solve': self.process_astap_solve_action,
            'import_asteroid_comet': self.import_asteroid_comet_action,
            'import_variable_star': self.import_variable_star_action,
            'image_list': self.image_list_action,
            'play_backward': self.play_backward_action,
            'play_forward': self.play_forward_action,
            'speed': self.speed_action,
            'goto': self.goto_action,
            'goto_radec': self.goto_radec_action,
            'zoom_in': self.zoom_in_action,
            'zoom_out': self.zoom_out_action,
            'draw_line': self.draw_line_action,
            'hide_lines': self.hide_lines_action,
            'line_settings': self.line_settings_action,
            'red_filter': self.red_filter_action,
            'green_filter': self.green_filter_action,
            'blue_filter': self.blue_filter_action,
            'reset_filter': self.reset_filter_action,
            'batch_photometry': self.photometry_action,
            'auto_animation': self.auto_animation_menu_action,
            'list_flatfield': self.process_batch_flatfield_action,
            'list_align': self.process_batch_align_new_action,
            'search_image': self.search_image_action,
            'settings': self.settings_action,
            'screen_stretch': self.screen_stretch_action,
            'measure': self.measure_action,
            'clear_measure': self.clear_measure_action,
            'crop': self.crop_action,
          }
        
        for key, action in shortcut_map.items():
            shortcut = self.get_shortcut(key)
            if shortcut and action:
                action.setShortcut(shortcut)
        
