        dialog = QDialog(self)
        dialog.setWindowTitle(_("stacking_settings"))
        dialog.setFixedSize(400, 550)
        
        layout = QVBoxLayout()
        dialog.setLayout(layout)
        
        # 亮度调整
        layout.addWidget(QLabel(f"- {_('brightness_adjust')} -"))
