    def show_photometry_window(self):
        """显示测光窗口"""
        try:
            # 检查窗口是否仍然有效，如果已被删除则重新创建
            if self.photometry_window is None:
                print("测光窗口为None，重新创建")
                self.photometry_window = PhotometryWindow(self, self)
            else:
                # 检查窗口是否仍然有效
                try:
                    # 尝试访问窗口的一个属性，如果窗口已被删除会抛出异常
                    _ = self.photometry_window.isVisible()
                    print("测光窗口仍然有效")
                except (RuntimeError, AttributeError) as e:
                    print(f"测光窗口已失效: {e}，重新创建")
                    self.photometry_window = PhotometryWindow(self, self)
            
            # 准备图像数据
            images_data = []
            for i, img_info in enumerate(self.images):
                try:
                    data = None
                    header = None
                    pixmap = None
                    
                    # 尝试从original_images获取数据
                    if i < len(self.original_images):
                        data = self.original_images[i]
                    
                    # 尝试从图像信息中获取pixmap
                    if 'pixmap' in img_info:
                        pixmap = img_info['pixmap']
                    
                    # 尝试从图像信息中获取header
                    if 'header' in img_info:
                        header = img_info['header']
                    
                    # 尝试从FITS文件中读取header
                    if header is None and hasattr(self, 'raw_fits_images') and i < len(self.raw_fits_images):
                        try:
                            from astropy.io import fits
                            # 如果有原始FITS数据，重新读取header
                            filename = img_info.get('filename', '')
                            if filename and filename.endswith('.fit'):
                                with fits.open(filename) as hdul:
                                    header = hdul[0].header
                        except Exception as e:
                            print(f"读取FITS header失败: {e}")
                    
                    # 获取图片对齐状态
                    is_aligned = img_info.get('aligned', False)
                    
                    image_info = {
                        'filename': img_info.get('filename', f'Image_{i+1}'),
                        'data': data,
                        'shape': str(data.shape) if data is not None else 'Unknown',
                        'header': header,  # 添加header信息
                        'pixmap': pixmap,  # 添加pixmap信息
                        'aligned': is_aligned  # 添加对齐状态信息
                    }
                    images_data.append(image_info)
                except Exception as e:
                    print(f"准备图像 {i} 数据时出错: {e}")
                    import traceback
                    traceback.print_exc()
                    continue
            
            if not images_data:
                QMessageBox.warning(self, "警告", "没有可用的图像数据！")
                return
            
            # 设置图像数据到测光窗口
            self.photometry_window.set_images(images_data)
            
            # 显示窗口
            self.photometry_window.show()
            self.photometry_window.raise_()
            self.photometry_window.activateWindow()
            
        except Exception as e:
            print(f"显示测光窗口时出错: {e}")
            import traceback
            traceback.print_exc()
            QMessageBox.critical(self, "错误", f"显示测光窗口时出错: {e}")
    
