            info_label.setAlignment(Qt.AlignCenter)
            layout.addWidget(info_label)
            
            # 添加滑块
            slider = QSlider(Qt.Horizontal)
            slider.setRange(5, 50)  # 0.5x-5x倍速
            slider.setValue(self.current_play_speed)  # 使用当前保存的播放速度值
            layout.addWidget(slider)
            
            # 添加显示标签
